:root {
  /* === Core Tailwind / shadcn tokens === */
  --background: #FAF9FF;
  --foreground: #12103A;
  --card: #FFFFFF;
  --card-foreground: #12103A;
  --popover: #FFFFFF;
  --popover-foreground: #12103A;
  --primary: #7C3AED;
  --primary-foreground: #FFFFFF;
  --secondary: #F3F0FF;
  --secondary-foreground: #3D3760;
  --muted: #F3F0FF;
  --muted-foreground: #3D3760;
  --accent: rgba(124, 58, 237, 0.12);
  --accent-foreground: #3D3760;
  --destructive: #EF4444;
  --destructive-foreground: #FFFFFF;
  --border: #DDD8F5;
  --input: #DDD8F5;
  --ring: #7C3AED;
  --chart-1: #7C3AED;
  --chart-2: #FF6B35;
  --chart-3: #10B981;
  --chart-4: #F59E0B;
  --chart-5: #3B82F6;
  --sidebar: #F3F0FF;
  --sidebar-foreground: #12103A;
  --sidebar-primary: #7C3AED;
  --sidebar-primary-foreground: #FFFFFF;
  --sidebar-accent: rgba(124, 58, 237, 0.12);
  --sidebar-accent-foreground: #3D3760;
  --sidebar-border: #DDD8F5;
  --sidebar-ring: #7C3AED;

  /* === Voltage brand palette === */
  --brand-primary: #7C3AED;
  --brand-secondary: #FF6B35;
  --brand-primary-subtle: #EDE9FE;
  --brand-secondary-subtle: #FFF0EB;

  /* === Voltage surfaces === */
  --bg-base: #FAF9FF;
  --bg-surface-1: #FFFFFF;
  --bg-surface-2: #F3F0FF;
  --bg-surface-3: #E8E4FF;
  --bg-surface-4: #DDD8F5;
  --bg-overlay: rgba(0, 0, 0, 0.4);

  /* === Accent violet === */
  --accent-primary: var(--primary);
  --accent-primary-hover: #6D28D9;
  --accent-primary-subtle: var(--accent);

  /* === Interactive === */
  --interactive: var(--ring);
  --interactive-hover: #6D28D9;
  --interactive-subtle: rgba(124, 58, 237, 0.10);

  /* === Semantic === */
  --positive: #10B981;
  --negative: #EF4444;
  --warning: #F59E0B;
  --info: #3B82F6;

  /* === Text === */
  --text-primary: var(--foreground);
  --text-secondary: var(--muted-foreground);
  --text-tertiary: #7B72A8;
  --text-on-accent: #FFFFFF;
  --text-price: var(--primary);

  /* === Typography === */
  --font-sans: var(--font-sans);
  --font-display: var(--font-barlow-condensed, ui-sans-serif);
  --font-mono: var(--font-geist-mono, ui-monospace);
  --font-serif: Merriweather, serif;
  --font-heading: var(--font-barlow, ui-sans-serif);
  --font-mono-stats: var(--font-dm-mono, ui-monospace);

  /* === Radius === */
  --radius: 0.625rem;

  /* === Shadows === */
  --shadow-2xs: 0px 4px 8px -1px hsl(0 0% 0% / 0.05);
  --shadow-xs: 0px 4px 8px -1px hsl(0 0% 0% / 0.05);
  --shadow-sm: 0px 4px 8px -1px hsl(0 0% 0% / 0.10), 0px 1px 2px -2px hsl(0 0% 0% / 0.10);
  --shadow: 0px 4px 8px -1px hsl(0 0% 0% / 0.10), 0px 1px 2px -2px hsl(0 0% 0% / 0.10);
  --shadow-md: 0px 4px 8px -1px hsl(0 0% 0% / 0.10), 0px 2px 4px -2px hsl(0 0% 0% / 0.10);
  --shadow-lg: 0px 4px 8px -1px hsl(0 0% 0% / 0.10), 0px 4px 6px -2px hsl(0 0% 0% / 0.10);
  --shadow-xl: 0px 4px 8px -1px hsl(0 0% 0% / 0.10), 0px 8px 10px -2px hsl(0 0% 0% / 0.10);
  --shadow-2xl: 0px 4px 8px -1px hsl(0 0% 0% / 0.25);
  --tracking-normal: 0em;
  --spacing: 0.25rem;

  /* === Neutral palette === */
  --neutral-0: 255, 255, 255;
  --neutral-25: 250, 249, 255;
  --neutral-50: 243, 240, 255;
  --neutral-100: 232, 228, 255;
  --neutral-200: 221, 216, 245;
  --neutral-300: 168, 159, 224;
  --neutral-400: 123, 114, 168;
  --neutral-500: 61, 55, 96;
  --neutral-600: 18, 16, 58;
  --neutral-700: 33, 32, 58;
  --neutral-800: 24, 22, 42;
  --neutral-900: 9, 9, 15;
  --neutral-1000: 9, 9, 15;

  /* === Brand palette (Violet scale) === */
  --brand-25: 245, 243, 255;
  --brand-50: 237, 233, 254;
  --brand-100: 221, 214, 254;
  --brand-200: 196, 181, 253;
  --brand-300: 167, 139, 250;
  --brand-400: 139, 92, 246;
  --brand-500: 124, 58, 237;
  --brand-600: 109, 40, 217;
  --brand-700: 91, 33, 182;
  --brand-800: 76, 29, 149;
  --brand-900: 46, 16, 101;

  /* === Red palette === */
  --red-25: 254, 243, 242;
  --red-50: 254, 228, 226;
  --red-100: 255, 205, 201;
  --red-200: 253, 170, 164;
  --red-300: 250, 121, 111;
  --red-400: 239, 68, 68;
  --red-500: 220, 38, 38;
  --red-600: 185, 28, 28;
  --red-700: 153, 27, 27;
  --red-800: 127, 29, 29;
  --red-900: 69, 10, 10;

  /* === Green palette === */
  --green-25: 236, 253, 245;
  --green-50: 209, 250, 229;
  --green-100: 167, 243, 208;
  --green-200: 110, 231, 183;
  --green-300: 52, 211, 153;
  --green-400: 16, 185, 129;
  --green-500: 5, 150, 105;
  --green-600: 4, 120, 87;
  --green-700: 6, 95, 70;
  --green-800: 6, 78, 59;
  --green-900: 6, 46, 34;

  /* === Yellow palette === */
  --yellow-25: 255, 251, 235;
  --yellow-50: 254, 243, 199;
  --yellow-100: 253, 230, 138;
  --yellow-200: 252, 211, 77;
  --yellow-300: 251, 191, 36;
  --yellow-400: 245, 158, 11;
  --yellow-500: 217, 119, 6;
  --yellow-600: 180, 83, 9;
  --yellow-700: 146, 64, 14;
  --yellow-800: 120, 53, 15;
  --yellow-900: 69, 26, 3;

  /* === Blue palette === */
  --blue-25: 239, 246, 255;
  --blue-50: 219, 234, 254;
  --blue-100: 191, 219, 254;
  --blue-200: 147, 197, 253;
  --blue-300: 96, 165, 250;
  --blue-400: 59, 130, 246;
  --blue-500: 37, 99, 235;
  --blue-600: 29, 78, 216;
  --blue-700: 30, 64, 175;
  --blue-800: 30, 58, 138;
  --blue-900: 23, 37, 84;

  /* === Game brand colors (light вҖ” darker for contrast on white) === */
  --game-mtg:     #7C3AED;
  --game-pokemon:  #D97706;
  --game-yugioh:   #2563EB;
  --game-optcg:    #059669;

  /* === Border strength === */
  --border-default: var(--border);
  --border-strong: #A89FD4;

  /* === Active border === */
  --border-active: rgba(124, 58, 237, 0.3);

  /* === TCG Rarity tokens (light вҖ” calibrated for #FFFFFF bg) === */

  /* MTG */
  --rarity-mtg-common: #6B7280;
  --rarity-mtg-uncommon: #6B9FBF;
  --rarity-mtg-rare: #B8860B;
  --rarity-mtg-mythic: #C2410C;

  /* MTG Mana (fixed game constants) */
  --mtg-white: #F9FAF4;
  --mtg-blue: #0E68AB;
  --mtg-black: #150B00;
  --mtg-red: #D3202A;
  --mtg-green: #00733E;
  --mtg-colorless: #A8A8A8;
  --mtg-gold: #B8860B;

  /* Pokemon */
  --rarity-poke-common: #6B7280;
  --rarity-poke-ultra: #6B7280;
  --rarity-poke-illustration: #92400E;
  --rarity-poke-hyper: #92400E;

  /* Yu-Gi-Oh */
  --rarity-ygo-common: #6B7280;
  --rarity-ygo-rare: #6B7280;
  --rarity-ygo-super: #0369A1;
  --rarity-ygo-ultra: #92400E;
  --rarity-ygo-secret: #6D28D9;
  --rarity-ygo-starlight: #374151;

  /* One Piece */
  --rarity-op-common: #6B7280;
  --rarity-op-uncommon: #1D4ED8;
  --rarity-op-rare: #15803D;
  --rarity-op-super: #92400E;
  --rarity-op-secret: #374151;
  --rarity-op-leader: #6D28D9;
}

.dark {
  /* === Core Tailwind / shadcn tokens === */
  --background: #09090F;
  --foreground: #F0EEFF;
  --card: #18162A;
  --card-foreground: #F0EEFF;
  --popover: #21203A;
  --popover-foreground: #F0EEFF;
  --primary: #8B5CF6;
  --primary-foreground: #09090F;
  --secondary: #18162A;
  --secondary-foreground: #B8B0D8;
  --muted: #18162A;
  --muted-foreground: #B8B0D8;
  --accent: rgba(139, 92, 246, 0.15);
  --accent-foreground: #F0EEFF;
  --destructive: #EF4444;
  --destructive-foreground: #09090F;
  --border: #2C2A4A;
  --input: #2C2A4A;
  --ring: #8B5CF6;
  --chart-1: #8B5CF6;
  --chart-2: #FF7849;
  --chart-3: #34D399;
  --chart-4: #FCD34D;
  --chart-5: #60A5FA;
  --sidebar: #18162A;
  --sidebar-foreground: #F0EEFF;
  --sidebar-primary: #8B5CF6;
  --sidebar-primary-foreground: #09090F;
  --sidebar-accent: rgba(139, 92, 246, 0.15);
  --sidebar-accent-foreground: #F0EEFF;
  --sidebar-border: #2C2A4A;
  --sidebar-ring: #8B5CF6;

  /* === Voltage brand palette === */
  --brand-primary: #8B5CF6;
  --brand-secondary: #FF7849;
  --brand-primary-subtle: #1E1A3A;
  --brand-secondary-subtle: #2A1A12;

  /* === Game brand colors (dark вҖ” brighter for contrast on dark bg) === */
  --game-mtg:     #A78BFA;
  --game-pokemon:  #FCD34D;
  --game-yugioh:   #60A5FA;
  --game-optcg:    #34D399;

  /* === Border strength === */
  --border-default: var(--border);
  --border-strong: #4A4680;

  /* === Active border === */
  --border-active: rgba(139, 92, 246, 0.3);

  /* === Voltage surfaces === */
  --bg-base: #09090F;
  --bg-surface-1: #18162A;
  --bg-surface-2: #21203A;
  --bg-surface-3: #2C2A4A;
  --bg-surface-4: #38365C;
  --bg-overlay: rgba(0, 0, 0, 0.6);

  /* === Accent violet === */
  --accent-primary: var(--primary);
  --accent-primary-hover: #A78BFA;
  --accent-primary-subtle: var(--accent);

  /* === Interactive === */
  --interactive: var(--ring);
  --interactive-hover: #A78BFA;
  --interactive-subtle: rgba(139, 92, 246, 0.12);

  /* === Semantic === */
  --positive: #10B981;
  --negative: #EF4444;
  --warning: #F59E0B;
  --info: #3B82F6;

  /* === Text === */
  --text-primary: var(--foreground);
  --text-secondary: var(--muted-foreground);
  --text-tertiary: #7B72A8;
  --text-on-accent: #09090F;
  --text-price: var(--primary);

  /* === Typography === */
  --font-display: var(--font-barlow-condensed, ui-sans-serif);
  --font-mono: var(--font-geist-mono, ui-monospace);
  --font-serif: Merriweather, serif;
  --font-heading: var(--font-barlow, ui-sans-serif);
  --font-mono-stats: var(--font-dm-mono, ui-monospace);

  /* === Radius === */
  --radius: 0.625rem;

  /* === Shadows === */
  --shadow-2xs: 0px 4px 8px -1px hsl(0 0% 0% / 0.15);
  --shadow-xs: 0px 4px 8px -1px hsl(0 0% 0% / 0.15);
  --shadow-sm: 0px 4px 8px -1px hsl(0 0% 0% / 0.25), 0px 1px 2px -2px hsl(0 0% 0% / 0.25);
  --shadow: 0px 4px 8px -1px hsl(0 0% 0% / 0.25), 0px 1px 2px -2px hsl(0 0% 0% / 0.25);
  --shadow-md: 0px 4px 8px -1px hsl(0 0% 0% / 0.25), 0px 2px 4px -2px hsl(0 0% 0% / 0.25);
  --shadow-lg: 0px 4px 8px -1px hsl(0 0% 0% / 0.25), 0px 4px 6px -2px hsl(0 0% 0% / 0.25);
  --shadow-xl: 0px 4px 8px -1px hsl(0 0% 0% / 0.25), 0px 8px 10px -2px hsl(0 0% 0% / 0.25);
  --shadow-2xl: 0px 4px 8px -1px hsl(0 0% 0% / 0.50);

  /* === TCG Rarity tokens (dark вҖ” calibrated for #18162A bg) === */

  /* MTG */
  --rarity-mtg-common: #9CA3AF;
  --rarity-mtg-uncommon: #93C5FD;
  --rarity-mtg-rare: #FCD34D;
  --rarity-mtg-mythic: #FB923C;

  /* Pokemon */
  --rarity-poke-common: #9CA3AF;
  --rarity-poke-ultra: #E2E8F0;
  --rarity-poke-illustration: #FCD34D;
  --rarity-poke-hyper: #FFD700;

  /* Yu-Gi-Oh */
  --rarity-ygo-common: #9CA3AF;
  --rarity-ygo-rare: #E2E8F0;
  --rarity-ygo-super: #7DD3FC;
  --rarity-ygo-ultra: #FCD34D;
  --rarity-ygo-secret: #DDD6FE;
  --rarity-ygo-starlight: #F8FAFC;

  /* One Piece */
  --rarity-op-common: #D1D5DB;
  --rarity-op-uncommon: #93C5FD;
  --rarity-op-rare: #6EE7B7;
  --rarity-op-super: #FCD34D;
  --rarity-op-secret: #F0EEFF;
  --rarity-op-leader: #DDD6FE;
}

@theme inline {
  --color-background: var(--background);
  --color-foreground: var(--foreground);
  --color-card: var(--card);
  --color-card-foreground: var(--card-foreground);
  --color-popover: var(--popover);
  --color-popover-foreground: var(--popover-foreground);
  --color-primary: var(--primary);
  --color-primary-foreground: var(--primary-foreground);
  --color-secondary: var(--secondary);
  --color-secondary-foreground: var(--secondary-foreground);
  --color-muted: var(--muted);
  --color-muted-foreground: var(--muted-foreground);
  --color-accent: var(--accent);
  --color-accent-foreground: var(--accent-foreground);
  --color-destructive: var(--destructive);
  --color-destructive-foreground: var(--destructive-foreground);
  --color-border: var(--border);
  --color-input: var(--input);
  --color-ring: var(--ring);
  --color-chart-1: var(--chart-1);
  --color-chart-2: var(--chart-2);
  --color-chart-3: var(--chart-3);
  --color-chart-4: var(--chart-4);
  --color-chart-5: var(--chart-5);
  --color-sidebar: var(--sidebar);
  --color-sidebar-foreground: var(--sidebar-foreground);
  --color-sidebar-primary: var(--sidebar-primary);
  --color-sidebar-primary-foreground: var(--sidebar-primary-foreground);
  --color-sidebar-accent: var(--sidebar-accent);
  --color-sidebar-accent-foreground: var(--sidebar-accent-foreground);
  --color-sidebar-border: var(--sidebar-border);
  --color-sidebar-ring: var(--sidebar-ring);

  /* Voltage surface tokens */
  --color-bg-base: var(--bg-base);
  --color-bg-surface-1: var(--bg-surface-1);
  --color-bg-surface-2: var(--bg-surface-2);
  --color-bg-surface-3: var(--bg-surface-3);
  --color-bg-surface-4: var(--bg-surface-4);
  --color-bg-overlay: var(--bg-overlay);

  /* Brand tokens */
  --color-brand-primary: var(--brand-primary);
  --color-brand-secondary: var(--brand-secondary);
  --color-brand-primary-subtle: var(--brand-primary-subtle);
  --color-brand-secondary-subtle: var(--brand-secondary-subtle);

  /* Accent + interactive */
  --color-accent-primary: var(--accent-primary);
  --color-interactive: var(--interactive);
  --color-interactive-subtle: var(--interactive-subtle);

  /* Semantic */
  --color-positive: var(--positive);
  --color-negative: var(--negative);
  --color-warning: var(--warning);
  --color-info: var(--info);

  /* Text tokens */
  --color-text-price: var(--text-price);
  --color-text-on-accent: var(--text-on-accent);

  /* Game brand colors */
  --color-game-mtg: var(--game-mtg);
  --color-game-pokemon: var(--game-pokemon);
  --color-game-yugioh: var(--game-yugioh);
  --color-game-optcg: var(--game-optcg);
  --color-border-active: var(--border-active);
  --color-border-default: var(--border-default);
  --color-border-strong: var(--border-strong);

  /* TCG Rarity вҖ” MTG */
  --color-rarity-mtg-common: var(--rarity-mtg-common);
  --color-rarity-mtg-uncommon: var(--rarity-mtg-uncommon);
  --color-rarity-mtg-rare: var(--rarity-mtg-rare);
  --color-rarity-mtg-mythic: var(--rarity-mtg-mythic);

  /* TCG Rarity вҖ” Pokemon */
  --color-rarity-poke-common: var(--rarity-poke-common);
  --color-rarity-poke-ultra: var(--rarity-poke-ultra);
  --color-rarity-poke-illustration: var(--rarity-poke-illustration);
  --color-rarity-poke-hyper: var(--rarity-poke-hyper);

  /* TCG Rarity вҖ” Yu-Gi-Oh */
  --color-rarity-ygo-common: var(--rarity-ygo-common);
  --color-rarity-ygo-rare: var(--rarity-ygo-rare);
  --color-rarity-ygo-super: var(--rarity-ygo-super);
  --color-rarity-ygo-ultra: var(--rarity-ygo-ultra);
  --color-rarity-ygo-secret: var(--rarity-ygo-secret);
  --color-rarity-ygo-starlight: var(--rarity-ygo-starlight);

  /* TCG Rarity вҖ” One Piece */
  --color-rarity-op-common: var(--rarity-op-common);
  --color-rarity-op-uncommon: var(--rarity-op-uncommon);
  --color-rarity-op-rare: var(--rarity-op-rare);
  --color-rarity-op-super: var(--rarity-op-super);
  --color-rarity-op-secret: var(--rarity-op-secret);
  --color-rarity-op-leader: var(--rarity-op-leader);

  --font-sans: var(--font-sans);
  --font-display: var(--font-display);
  --font-mono: var(--font-mono);
  --font-serif: var(--font-serif);
  --font-heading: var(--font-heading);
  --font-mono-stats: var(--font-mono-stats);

  --radius-sm: calc(var(--radius) - 4px);
  --radius-md: calc(var(--radius) - 2px);
  --radius-lg: var(--radius);
  --radius-xl: calc(var(--radius) + 4px);

  --shadow-2xs: var(--shadow-2xs);
  --shadow-xs: var(--shadow-xs);
  --shadow-sm: var(--shadow-sm);
  --shadow: var(--shadow);
  --shadow-md: var(--shadow-md);
  --shadow-lg: var(--shadow-lg);
  --shadow-xl: var(--shadow-xl);
  --shadow-2xl: var(--shadow-2xl);
}

/* Defined colors variables */
@import "colors.css";

@tailwind base;
@tailwind components;
@tailwind utilities;

/* Typography */
.text-xl {
  @apply font-light tracking-normal;
}
.text-lg {
  @apply text-base font-light tracking-normal;
}
.text-md {
  @apply text-[14px] leading-[22px] font-light tracking-normal;
}
.text-sm {
  @apply text-[12px] font-light tracking-normal;
}

.label-sm {
  @apply text-[12px] leading-[20px] font-normal tracking-normal;
}
.label-md {
  @apply text-[14px] leading-[22px] font-normal tracking-normal;
}
.label-lg {
  @apply text-[16px] leading-[24px] font-semibold tracking-normal;
}
.label-xl {
  @apply text-[20px] leading-[28px] font-semibold tracking-normal;
}

.heading-xs {
  font: 600 16px/1.4 var(--font-heading);
}
.heading-sm {
  font: 600 20px/1.3 var(--font-heading);
}
.heading-md {
  font: 600 24px/1.25 var(--font-heading);
}
.heading-lg {
  font: 600 32px/1.2 var(--font-display);
}
.heading-xl {
  font: 600 40px/1.15 var(--font-display);
}

.display-sm {
  font: 700 56px/1.1 var(--font-display);
  letter-spacing: -0.02em;
}
.display-md {
  font: 700 56px/1.1 var(--font-display);
  letter-spacing: -0.02em;
}
.display-lg {
  font: 800 72px/1.05 var(--font-display);
  letter-spacing: -0.02em;
}

@media (max-width: 768px) {
  .heading-md { font-size: 20px; line-height: 1.3; }
  .heading-lg { font-size: 24px; line-height: 1.25; }
  .heading-xl { font-size: 32px; line-height: 1.2; }
  .display-sm { font-size: 32px; line-height: 1.2; }
  .display-md { font-size: 40px; line-height: 1.15; }
  .display-lg { font-size: 56px; line-height: 1.1; }
}
.container {
  @apply px-4 md:px-5 max-w-full w-full lg:py-8 py-4 lg:px-8;
}

/* Nav component utilities */
.nav-icon-action {
  position: relative;
  width: 36px;
  height: 36px;
  border-radius: 10px;
  border: 1px solid transparent;
  background: transparent;
  color: var(--muted-foreground);
  display: flex;
  align-items: center;
  justify-content: center;
  cursor: pointer;
  transition: all 0.15s;
}
.nav-icon-action:hover {
  background: var(--bg-surface-2);
  color: var(--foreground);
  border-color: var(--border-default);
}

.search-pill {
  background: var(--bg-surface-2);
  border-color: var(--border-default);
  color: var(--text-tertiary);
}
.search-pill:hover {
  border-color: var(--border-strong);
}

/* Atoms components */

.button-icon {
  @apply bg-primary hover:bg-action-secondary-hover active:bg-action-secondary-pressed disabled:bg-primary;
}
.button-icon svg path {
  @apply fill-secondary;
}

.button-filled {
  @apply bg-action hover:bg-action-hover active:bg-action-pressed disabled:bg-disabled;
}
.button-filled svg path {
  @apply fill-primary-foreground;
}

.button-tonal {
  @apply bg-action-secondary hover:bg-action-secondary-hover active:bg-action-secondary-pressed disabled:bg-disabled;
}
.button-tonal svg path {
  @apply fill-secondary;
}

button:disabled svg path {
  @apply fill-disabled;
}

.button-text-filled svg path {
  @apply fill-tertiary;
}

.checkbox-wrapper {
  @apply rounded-xs bg-component-secondary w-[20px] h-[20px] border border-secondary bg-component-secondary cursor-pointer;
}
.checkbox-wrapper svg {
  @apply pointer-events-none;
}
.checkbox-wrapper svg path {
  @apply fill-primary;
}

.chip-wrapper {
  @apply bg-component inline-flex items-center px-3 py-1 rounded-sm label-sm border hover:bg-component-hover relative;
}
.chip-wrapper svg path {
  @apply fill-secondary;
}
.chip-wrapper[data-disabled="true"] svg path {
  @apply fill-primary;
}

.multi-gradient {
  background: conic-gradient(
    from 180deg at 50% 50%,
    #00438f 0deg,
    #4da0ff 50.4deg,
    #17a34a 108deg,
    #ffbf38 165.6deg,
    #c56a09 217.8deg,
    #d92d20 282.6deg,
    #00438f 360deg
  );
}
.no-scrollbar::-webkit-scrollbar {
  display: none;
}
.no-scrollbar {
  -ms-overflow-style: none;
  scrollbar-width: none;
}
.product-details {
  @apply text-md;
}
.product-details ul {
  @apply list-disc text-md pl-5;
}
.embla__container {
  touch-action: pan-y pinch-zoom;
}
.embla__slide {
  transform: translate3d(0, 0, 0);
  flex: 0 0 100%;
  min-width: 0;
}

/* Modern Header Animations */
@keyframes fadeIn {
  from { 
    opacity: 0; 
    transform: translateY(-10px); 
  }
  to { 
    opacity: 1; 
    transform: translateY(0); 
  }
}

@keyframes slideInLeft {
  from { 
    transform: translateX(-100%); 
    opacity: 0; 
  }
  to { 
    transform: translateX(0); 
    opacity: 1; 
  }
}

@keyframes scaleIn {
  from { 
    transform: scale(0); 
    opacity: 0; 
  }
  to { 
    transform: scale(1); 
    opacity: 1; 
  }
}

@keyframes bounceIn {
  0% { 
    transform: scale(0); 
    opacity: 0; 
  }
  50% { 
    transform: scale(1.2); 
    opacity: 0.8; 
  }
  100% { 
    transform: scale(1); 
    opacity: 1; 
  }
}

.animate-fadeIn { 
  animation: fadeIn 0.2s ease-out; 
}

.animate-slideInLeft { 
  animation: slideInLeft 0.3s ease-out; 
}

.animate-scaleIn { 
  animation: scaleIn 0.3s ease-out; 
}

.animate-bounceIn { 
  animation: bounceIn 0.4s ease-out; 
}

/* Price typography вҖ” tabular figures, brand primary */
.price {
  font-family: var(--font-mono-stats);
  font-feature-settings: 'tnum';
  font-weight: 500;
  color: var(--text-price);
}

/* TCG card aspect ratio вҖ” standard playing card 2.5" x 3.5" */
.card-aspect {
  aspect-ratio: 2.5 / 3.5;
}

/* Pointer-adaptive density (for seller table) */
@media (pointer: fine) {
  .density-adaptive-row {
    @apply h-8;
  }
}
@media (pointer: coarse) {
  .density-adaptive-row {
    @apply h-11;
  }
}

/* Backdrop blur support */
@supports (backdrop-filter: blur(12px)) {
  .backdrop-blur-xl {
    backdrop-filter: blur(12px);
  }
  .backdrop-blur-md {
    backdrop-filter: blur(8px);
  }
}

/* Smooth scrolling for the entire page */
html {
  scroll-behavior: smooth;
}

/* Better focus states for accessibility */
.focus-ring {
  @apply focus:outline-none focus:ring-2 focus:ring-action focus:ring-opacity-50 focus:ring-offset-2;
}

/* Accent CTA button вҖ” used by WhySidedeckedCard */
.accent-cta-btn {
  background-color: rgba(139, 92, 246, 0.10);
  color: var(--accent-primary);
  border: 1px solid rgba(139, 92, 246, 0.30);
  transition: background-color 150ms ease-out;
}
.accent-cta-btn:hover {
  background-color: rgba(139, 92, 246, 0.18);
}

/* Voltage motion вҖ” card hover glow */
.card-glow {
  transition: box-shadow 150ms ease-out;
}
.card-glow:hover {
  box-shadow: 0 0 24px rgba(139, 92, 246, 0.4);
}

/* Voltage motion вҖ” brand pulse (loading states) */
@keyframes brand-pulse {
  0%, 100% { opacity: 1; }
  50% { opacity: 0.5; }
}
.animate-brand-pulse {
  animation: brand-pulse 2s ease-in-out infinite;
}

/* Voltage motion вҖ” gradient sweep (hero sections, banners) */
@keyframes gradient-sweep {
  0% { background-position: 0% 50%; }
  50% { background-position: 100% 50%; }
  100% { background-position: 0% 50%; }
}
.animate-gradient-sweep {
  background-size: 200% 200%;
  animation: gradient-sweep 6s ease infinite;
}

"use client"

import { useState, useEffect } from "react"
import { useTheme } from "next-themes"
import { HttpTypes } from "@medusajs/types"
import { usePathname } from "next/navigation"
import LocalizedClientLink from "@/components/molecules/LocalizedLink/LocalizedLink"
import { SideDeckedLogo } from "@/components/atoms/SideDeckedLogo"
import { Wishlist } from "@/types/wishlist"
import { EnhancedSearchBar } from "@/components/search/EnhancedSearchBar"
import { Moon, Sun, Bell, Heart, ShoppingBag, Menu, X, User } from "lucide-react"

interface ModernHeaderProps {
  cart: HttpTypes.StoreCart | null
  user: HttpTypes.StoreCustomer | null
  wishlist: Wishlist[]
  categories: HttpTypes.StoreProductCategory[]
  parentCategories: HttpTypes.StoreProductCategory[]
  regions: any[]
  isSeller?: boolean
}

const navLinks = [
  { href: "/cards", label: "Browse Cards" },
  { href: "/decks", label: "Deck Builder" },
  { href: "/marketplace", label: "Marketplace" },
  { href: "/sell", label: "Sell" },
  { href: "/community", label: "Community" },
]

export const ModernHeader = ({
  cart,
  user,
  wishlist,
  categories,
  parentCategories,
  regions,
  isSeller = false,
}: ModernHeaderProps) => {
  const [mobileMenuOpen, setMobileMenuOpen] = useState(false)
  const [mounted, setMounted] = useState(false)
  const pathname = usePathname()
  const { theme, setTheme } = useTheme()

  const cartItemsCount =
    cart?.items?.reduce((acc, item) => acc + item.quantity, 0) || 0
  const wishlistCount = wishlist?.[0]?.products.length || 0

  useEffect(() => {
    setMounted(true)
  }, [])

  if (!mounted) {
    return (
      <header className="sticky top-0 left-0 right-0 z-[1000] h-16 bg-secondary/60 backdrop-blur-[16px]">
        <div className="flex items-center h-16 w-full max-w-[1344px] mx-auto px-8 gap-6">
          <div className="w-32 h-6 bg-muted animate-pulse rounded" />
          <div className="hidden lg:flex flex-1 max-w-[420px] h-9 bg-muted animate-pulse rounded-full" />
          <div className="flex items-center gap-1.5 ml-auto">
            {[...Array(4)].map((_, i) => (
              <div
                key={i}
                className="w-9 h-9 bg-muted animate-pulse rounded-[10px]"
              />
            ))}
            <div className="w-8 h-8 bg-muted animate-pulse rounded-full" />
          </div>
        </div>
      </header>
    )
  }

  const toggleTheme = () => {
    setTheme(theme === "dark" ? "light" : "dark")
  }

  const isDark = theme === "dark"

  return (
    <>
      {/* Desktop Header */}
      <header
        className="sticky top-0 z-[1000] h-16 hidden lg:flex items-center border-b px-8"
        style={{
          background: isDark
            ? "rgba(24, 22, 42, 0.60)"
            : "rgba(255, 255, 255, 0.60)",
          backdropFilter: "blur(16px)",
          WebkitBackdropFilter: "blur(16px)",
          borderBottomColor: "rgba(139, 92, 246, 0.08)",
        }}
      >
        <div className="flex items-center h-16 w-full max-w-[1344px] mx-auto gap-6">
          {/* Logo */}
          <LocalizedClientLink
            href="/"
            className="flex-shrink-0"
          >
            <SideDeckedLogo variant="text" fontSize={24} />
          </LocalizedClientLink>

          {/* Nav Links */}
          <nav className="flex gap-2 ml-4">
            {navLinks.map((link) => (
              <LocalizedClientLink
                key={link.href}
                href={link.href}
                className={`
                  font-heading text-sm font-medium px-3.5 py-2 rounded-[10px]
                  transition-all duration-150
                  ${
                    pathname === link.href
                      ? "text-foreground"
                      : "text-muted-foreground hover:text-foreground hover:bg-[rgba(139,92,246,0.08)]"
                  }
                `}
              >
                {link.label}
              </LocalizedClientLink>
            ))}
          </nav>

          {/* Search */}
          <EnhancedSearchBar
            placeholder="Search cards, sets, sellers..."
            className="flex-1 max-w-[420px]"
          />

          {/* Actions */}
          <div className="flex items-center gap-1.5 flex-shrink-0">
            {/* Theme Toggle */}
            <button
              onClick={toggleTheme}
              className="nav-icon-action"
              aria-label="Toggle theme"
            >
              {isDark ? <Moon size={18} /> : <Sun size={18} />}
            </button>

            {/* Notifications (auth-gated) */}
            {user && (
              <button className="nav-icon-action" aria-label="Notifications">
                <Bell size={18} />
                <span
                  className="absolute top-1.5 right-1.5 w-2 h-2 rounded-full"
                  style={{
                    background: "var(--brand-secondary)",
                    border: "2px solid var(--bg-surface-1)",
                  }}
                />
              </button>
            )}

            {/* Wishlist (auth-gated) */}
            {user && (
              <LocalizedClientLink
                href="/user/wishlist"
                className="nav-icon-action"
              >
                <Heart size={18} />
                {wishlistCount > 0 && (
                  <span
                    className="absolute top-1 right-1 w-3.5 h-3.5 rounded-full text-white text-[9px] font-semibold flex items-center justify-center leading-none"
                    style={{ background: "var(--brand-secondary)" }}
                  >
                    {wishlistCount}
                  </span>
                )}
              </LocalizedClientLink>
            )}

            {/* Cart */}
            <LocalizedClientLink href="/cart" className="nav-icon-action">
              <ShoppingBag size={18} />
              {cartItemsCount > 0 && (
                <span
                  className="absolute top-1 right-1 w-3.5 h-3.5 rounded-full text-white text-[9px] font-semibold flex items-center justify-center leading-none"
                  style={{ background: "var(--brand-secondary)" }}
                >
                  {cartItemsCount}
                </span>
              )}
            </LocalizedClientLink>

            {/* Profile Avatar */}
            <div className="relative group">
              <button className="w-8 h-8 rounded-full bg-gradient-to-br from-[var(--brand-primary)] to-[#A78BFA] ml-1 flex-shrink-0 flex items-center justify-center cursor-pointer">
                {user ? (
                  <span className="font-heading text-xs font-semibold text-white">
                    {user.first_name?.[0] || user.email?.[0]?.toUpperCase()}
                  </span>
                ) : (
                  <User size={14} className="text-white" />
                )}
              </button>

              {/* Dropdown Menu */}
              <div
                className="
                  absolute right-0 top-full mt-2 w-56
                  rounded-2xl shadow-2xl border
                  opacity-0 invisible group-hover:opacity-100 group-hover:visible
                  transition-all duration-200 transform origin-top-right
                  scale-95 group-hover:scale-100
                "
                style={{
                  background: "var(--secondary)",
                  borderColor: "var(--border)",
                }}
              >
                {user ? (
                  <>
                    <div
                      className="p-4 border-b"
                      style={{ borderColor: "var(--border)" }}
                    >
                      <div className="font-medium text-sm text-foreground">
                        {user.first_name} {user.last_name}
                      </div>
                      <div className="text-xs text-muted-foreground">
                        {user.email}
                      </div>
                    </div>
                    <div className="p-2">
                      <LocalizedClientLink
                        href="/user/orders"
                        className="flex items-center px-3 py-2 rounded-lg text-sm text-foreground hover:bg-[rgba(139,92,246,0.08)] transition-colors duration-150"
                      >
                        Orders
                      </LocalizedClientLink>
                      <LocalizedClientLink
                        href="/user/messages"
                        className="flex items-center px-3 py-2 rounded-lg text-sm text-foreground hover:bg-[rgba(139,92,246,0.08)] transition-colors duration-150"
                      >
                        Messages
                      </LocalizedClientLink>
                      <LocalizedClientLink
                        href="/user/settings"
                        className="flex items-center px-3 py-2 rounded-lg text-sm text-foreground hover:bg-[rgba(139,92,246,0.08)] transition-colors duration-150"
                      >
                        Settings
                      </LocalizedClientLink>
                      <hr
                        className="my-2"
                        style={{ borderColor: "var(--border)" }}
                      />
                      <LocalizedClientLink
                        href={isSeller ? "/sell" : "/sell/upgrade"}
                        className="flex items-center px-3 py-2 rounded-lg text-sm text-primary hover:bg-[rgba(139,92,246,0.08)] transition-colors duration-150"
                      >
                        {isSeller ? "Seller Dashboard" : "Become a Seller"}
                      </LocalizedClientLink>
                      <button
                        onClick={async () => {
                          try {
                            const response = await fetch("/api/logout", {
                              method: "POST",
                              credentials: "include",
                            })
                            if (!response.ok) {
                              console.warn("Logout response not ok:", response.status)
                            }
                            if (typeof localStorage !== "undefined") {
                              try {
                                localStorage.clear()
                              } catch (error) {
                                console.warn(
                                  "Failed to clear localStorage:",
                                  error
                                )
                              }
                            }
                            if (typeof sessionStorage !== "undefined") {
                              try {
                                sessionStorage.clear()
                              } catch (error) {
                                console.warn(
                                  "Failed to clear sessionStorage:",
                                  error
                                )
                              }
                            }
                            window.location.href = "/"
                          } catch (error) {
                            console.error("Logout error:", error)
                            window.location.href = "/"
                          }
                        }}
                        className="w-full text-left px-3 py-2 rounded-lg text-sm text-destructive hover:bg-destructive/10 transition-colors duration-150"
                      >
                        Sign Out
                      </button>
                    </div>
                  </>
                ) : (
