                    <LocalizedClientLink
                      href="/user"
                      className="flex items-center justify-center px-3 py-2 rounded-lg text-sm font-medium transition-colors duration-150 hover:opacity-90"
                      style={{
                        background: "var(--brand-primary)",
                        color: "var(--text-on-accent)",
                      }}
                    >
                      Sign In
                    </LocalizedClientLink>
                    <LocalizedClientLink
                      href="/user/register"
                      className="flex items-center justify-center px-3 py-2 mt-2 rounded-lg text-sm font-medium transition-colors duration-150 hover:bg-[rgba(139,92,246,0.08)]"
                      style={{
                        border: "1px solid var(--border-default)",
                        color: "var(--text-primary)",
                      }}
                    >
                      Create Account
                    </LocalizedClientLink>
                  </div>
                )}
              </div>
            </div>
          </div>
        </div>
      </header>

      {/* Mobile Header */}
      <header
        className="sticky top-0 z-[1000] lg:hidden flex flex-col"
        style={{
          background: isDark
            ? "rgba(24, 22, 42, 0.80)"
            : "rgba(255, 255, 255, 0.80)",
          backdropFilter: "blur(12px)",
          WebkitBackdropFilter: "blur(12px)",
          borderBottom: isDark
            ? "1px solid rgba(44, 42, 74, 0.5)"
            : "1px solid rgba(221, 216, 245, 0.5)",
          padding: "0 20px",
        }}
      >
        {/* Top row */}
        <div className="flex items-center h-14 justify-between">
          <button
            onClick={() => setMobileMenuOpen(!mobileMenuOpen)}
            className="p-1 flex items-center justify-center text-muted-foreground"
            aria-label="Toggle menu"
          >
            {mobileMenuOpen ? <X size={18} /> : <Menu size={18} />}
          </button>

          <LocalizedClientLink
            href="/"
            className="flex-1 text-center"
          >
            <SideDeckedLogo variant="text" fontSize={20} />
          </LocalizedClientLink>

          <div className="flex items-center gap-1">
            <LocalizedClientLink
              href="/cart"
              className="relative w-8 h-8 rounded-lg flex items-center justify-center text-muted-foreground"
            >
              <ShoppingBag size={16} />
              {cartItemsCount > 0 && (
                <span
                  className="absolute top-0 right-0 w-3.5 h-3.5 rounded-full text-white text-[8px] font-semibold flex items-center justify-center leading-none"
                  style={{ background: "var(--brand-secondary)" }}
                >
                  {cartItemsCount}
                </span>
              )}
            </LocalizedClientLink>

            <LocalizedClientLink href="/user">
              <div
                className="w-7 h-7 rounded-full flex items-center justify-center flex-shrink-0"
                style={{
                  background:
                    "linear-gradient(135deg, var(--brand-primary), var(--brand-secondary))",
                  border: "2px solid var(--brand-primary)",
                  boxShadow: "0 0 12px rgba(139, 92, 246, 0.4)",
                }}
              >
                {user ? (
                  <span className="font-heading text-[10px] font-bold text-white">
                    {user.first_name?.[0] || user.email?.[0]?.toUpperCase()}
                  </span>
                ) : (
                  <User size={12} className="text-white" />
                )}
              </div>
            </LocalizedClientLink>
          </div>
        </div>

        {/* Search row */}
        <div className="pb-2.5">
          <EnhancedSearchBar
            placeholder="Search cards, sets, sellers..."
            compact
            className="w-full"
          />
        </div>
      </header>

      {/* Mobile Menu Overlay */}
      {mobileMenuOpen && (
        <div
          className="fixed inset-0 z-[999] bg-black/50 backdrop-blur-sm lg:hidden"
          onClick={() => setMobileMenuOpen(false)}
        >
          <div
            className="w-80 h-full shadow-2xl"
            style={{ background: "var(--secondary)" }}
            onClick={(e) => e.stopPropagation()}
          >
            <div className="p-4">
              <SideDeckedLogo variant="text" fontSize={22} />
            </div>
            <nav className="p-4 space-y-2">
              {navLinks.map((link) => (
                <LocalizedClientLink
                  key={link.href}
                  href={link.href}
                  className={`
                    flex items-center px-4 py-3 rounded-lg text-sm font-medium
                    transition-colors duration-150
                    ${
                      pathname === link.href
                        ? "text-foreground bg-[rgba(139,92,246,0.08)]"
                        : "text-muted-foreground hover:text-foreground hover:bg-[rgba(139,92,246,0.08)]"
                    }
                  `}
                  onClick={() => setMobileMenuOpen(false)}
                >
                  {link.label}
                </LocalizedClientLink>
              ))}
            </nav>
            <div className="p-4 border-t" style={{ borderColor: "var(--border)" }}>
              <button
                onClick={toggleTheme}
                className="flex items-center gap-3 px-4 py-3 rounded-lg text-sm text-muted-foreground hover:text-foreground hover:bg-[rgba(139,92,246,0.08)] w-full transition-colors duration-150"
              >
                {isDark ? <Moon size={16} /> : <Sun size={16} />}
                {isDark ? "Dark Mode" : "Light Mode"}
              </button>
            </div>
          </div>
        </div>
      )}

    </>
  )
}

"use client"

import { useState, useEffect } from "react"
import Link from "next/link"
import type { Card, SearchResult } from "@/types/tcg"
import {
  getCardImageUrl,
  getCardRarity,
  getCardBlurhash,
} from "@/lib/data/cards"
import { BlurHashImage } from "@/components/common/BlurHashImage"
import { RarityBadge } from "@/components/tcg/RarityBadge"
import { PriceTag } from "@/components/tcg/PriceTag"
import { GameBadge } from "@/components/tcg/GameBadge"
import { cn } from "@/lib/utils"

export type CardDisplayVariant = "gallery" | "grid" | "list" | "compact"

interface CardDisplayProps {
  card: Card
  searchResult?: SearchResult
  variant: CardDisplayVariant
  price?: number | null
  sellerCount?: number
  priceTrend?: "up" | "down" | "stable"
  isSelected?: boolean
  showSelection?: boolean
  onSelect?: () => void
  onClick?: () => void
  draggable?: boolean
  onDragStart?: (e: React.DragEvent) => void
  className?: string
}

type ImageSize = "normal" | "small" | "thumbnail"

function useCardImageState(card: Card, variant: CardDisplayVariant) {
  const [imageError, setImageError] = useState(false)
  const [retryCount, setRetryCount] = useState(0)
  const [currentSize, setCurrentSize] = useState<ImageSize>("normal")

  const componentType = variant === "list" || variant === "compact" ? "thumbnail" : "grid"

  const cardId = card.id
  useEffect(() => {
    setImageError(false)
    setRetryCount(0)
    setCurrentSize("normal")
  }, [cardId])

  const imageUrl =
    imageError || retryCount > 0
      ? getCardImageUrl(card, currentSize)
      : getCardImageUrl(card, { componentType, prioritizeQuality: false })

  const handleError = () => {
    if (retryCount < 2) {
      if (currentSize === "normal") {
        setCurrentSize("small")
        setRetryCount(prev => prev + 1)
        setImageError(false)
      } else if (currentSize === "small") {
        setCurrentSize("thumbnail")
        setRetryCount(prev => prev + 1)
        setImageError(false)
      } else {
        setImageError(true)
      }
    } else {
      setImageError(true)
    }
  }

  const handleLoad = () => {
    setImageError(false)
  }

  return { imageUrl, imageError, handleError, handleLoad }
}

function NoImagePlaceholder({ compact = false }: { compact?: boolean }) {
  return (
    <div className="w-full h-full bg-muted rounded flex items-center justify-center">
      {compact ? (
        <span className="text-xs text-muted-foreground">?</span>
      ) : (
        <span className="text-xs text-muted-foreground">No Image</span>
      )}
    </div>
  )
}

function interactiveArticleProps(onClick?: () => void) {
  if (!onClick) return {}
  return {
    tabIndex: 0,
    onKeyDown: (e: React.KeyboardEvent) => {
      if (e.key === "Enter" || e.key === " ") {
        e.preventDefault()
        onClick()
      }
    },
