import { cn } from "@/lib/utils"

export type PriceTagVariant = 'inline' | 'detailed' | 'compact'
type TrendDirection = 'up' | 'down' | 'stable'

interface PriceTagProps {
  price: number | null
  sellerCount?: number
  marketAvg?: number
  trend?: TrendDirection
  variant: PriceTagVariant
  className?: string
}

function formatPrice(price: number): string {
  return new Intl.NumberFormat('en-US', {
    style: 'currency',
    currency: 'USD',
    minimumFractionDigits: 2,
  }).format(price)
}

function sellerLabel(count: number): string {
  return count === 1 ? '1 seller' : `${count} sellers`
}

function TrendIcon({ direction }: { direction: TrendDirection }) {
  if (direction === 'stable') return null
  const isDown = direction === 'down'
  return (
    <span
      aria-label={`trending ${direction}`}
      role="img"
      style={{ color: isDown ? 'var(--positive)' : 'var(--warning)' }}
    >
      {isDown ? 'вҶ“' : 'вҶ‘'}
    </span>
  )
}

function NoSellers({ className }: { className?: string }) {
  return (
    <span
      role="group"
      aria-label="No sellers available"
      className={cn('text-sm', className)}
      style={{ color: 'var(--muted-foreground)' }}
    >
      No sellers
    </span>
  )
}

export function PriceTag({
  price,
  sellerCount,
  marketAvg,
  trend,
  variant,
  className,
}: PriceTagProps) {
  if (price === null || price === undefined) {
    return <NoSellers className={className} />
  }

  const formattedPrice = formatPrice(price)
  const formattedMarketAvg = marketAvg != null ? formatPrice(marketAvg) : null

  const ariaLabel = [
    formattedPrice,
    sellerCount != null ? sellerLabel(sellerCount) : null,
  ]
    .filter(Boolean)
    .join(', ')

  if (variant === 'compact') {
    return (
      <span
        role="group"
        aria-label={ariaLabel || formattedPrice}
        className={cn('text-sm font-semibold', className)}
        style={{ color: 'var(--text-price)' }}
      >
        {formattedPrice}
      </span>
    )
  }

  if (variant === 'inline') {
    return (
      <span
        role="group"
        aria-label={ariaLabel}
        className={cn('inline-flex items-center gap-1 text-sm', className)}
      >
        <span className="font-semibold" style={{ color: 'var(--text-price)' }}>
          {formattedPrice}
        </span>
        {sellerCount != null && sellerCount > 0 && (
          <span style={{ color: 'var(--muted-foreground)' }}>
            В· {sellerLabel(sellerCount)}
          </span>
        )}
        {trend && trend !== 'stable' && <TrendIcon direction={trend} />}
      </span>
    )
  }

  // detailed
  return (
    <span
      role="group"
      aria-label={ariaLabel}
      className={cn('inline-flex items-center gap-1 text-sm flex-wrap', className)}
    >
      <span className="font-semibold" style={{ color: 'var(--text-price)' }}>
        {formattedPrice}
      </span>
      {sellerCount != null && sellerCount > 0 && (
        <span style={{ color: 'var(--muted-foreground)' }}>
          В· from {sellerLabel(sellerCount)}
        </span>
      )}
      {formattedMarketAvg && (
        <span style={{ color: 'var(--muted-foreground)' }}>
          В· market avg {formattedMarketAvg}
        </span>
      )}
      {trend && trend !== 'stable' && <TrendIcon direction={trend} />}
    </span>
  )
}

"use client"

import { useGridColumns } from "@/hooks/useGridColumns"

interface Props {
  viewMode?: 'grid' | 'list'
  count?: number
}

export function CardGridSkeleton({ viewMode = 'grid', count = 24 }: Props) {
  const { gridClass, columns } = useGridColumns()
  
  // Adjust skeleton count based on grid columns for better UX
  const adjustedCount = Math.max(count, columns * 3) // Show at least 3 rows

  if (viewMode === 'list') {
    return (
      <div className="space-y-4">
        {Array.from({ length: adjustedCount }).map((_, i) => (
          <div key={i} className="flex items-center space-x-4 p-4 bg-card rounded-lg border border-border animate-pulse">
            <div className="flex-shrink-0 w-16 card-aspect bg-muted rounded" />
            <div className="flex-1 space-y-2">
              <div className="h-4 bg-muted rounded w-3/4" />
              <div className="h-3 bg-muted rounded w-1/2" />
              <div className="h-3 bg-muted rounded w-1/4" />
            </div>
            <div className="flex-shrink-0 space-y-2">
              <div className="h-6 w-12 bg-muted rounded" />
              <div className="h-3 w-16 bg-muted rounded" />
            </div>
          </div>
        ))}
      </div>
    )
  }

  return (
    <div className={gridClass}>
      {Array.from({ length: adjustedCount }).map((_, i) => (
        <div key={i} className="bg-card rounded-lg border border-border animate-pulse">
          <div className="card-aspect w-full bg-muted rounded-t-lg" />
          <div className="p-3 space-y-2">
            <div className="h-4 bg-muted rounded" />
            <div className="h-3 bg-muted rounded w-3/4" />
            <div className="h-3 bg-muted rounded w-1/2" />
          </div>
        </div>
      ))}
    </div>
  )
}

