import { HttpTypes } from "@medusajs/types"
import { listCategories } from "@/lib/data/categories"
import { PARENT_CATEGORIES } from "@/const"
import { retrieveCart } from "@/lib/data/cart"
import { retrieveCustomer, getCustomerProfile } from "@/lib/data/customer"
import { getUserWishlists } from "@/lib/data/wishlist"
import { Wishlist } from "@/types/wishlist"
import { listRegions } from "@/lib/data/regions"
import { ModernHeader } from './ModernHeader'

export const Header = async () => {
  const cart = await retrieveCart().catch(() => null)
  const user = await retrieveCustomer()
  let wishlist: Wishlist[] = []
  let isSeller = false
  if (user) {
    const response = await getUserWishlists()
    wishlist = response.wishlists
    const profile = await getCustomerProfile(user.id).catch(() => null)
    isSeller = profile?.is_seller ?? false
  }

  const regions = await listRegions()

  const { categories, parentCategories } = (await listCategories({
    headingCategories: PARENT_CATEGORIES,
  })) as {
    categories: HttpTypes.StoreProductCategory[]
    parentCategories: HttpTypes.StoreProductCategory[]
  }

  return (
    <ModernHeader
      cart={cart}
      user={user}
      wishlist={wishlist}
      categories={categories}
      parentCategories={parentCategories}
      regions={regions}
      isSeller={isSeller}
    />
  )
}

import { Footer, Header } from "@/components/organisms"
import { retrieveCustomer, getCustomerProfile } from "@/lib/data/customer"
import { checkRegion } from "@/lib/helpers/check-region"
import { OnboardingModal } from "@/components/profile/OnboardingModal"
import { Session } from "@talkjs/react"
import { redirect } from "next/navigation"

export default async function RootLayout({
  children,
  params,
}: Readonly<{
  children: React.ReactNode
  params: Promise<{ locale: string }>
}>) {
  const APP_ID = process.env.NEXT_PUBLIC_TALKJS_APP_ID
  const { locale } = await params

  const user = await retrieveCustomer()
  const regionCheck = await checkRegion(locale)
  const customerProfile = user ? await getCustomerProfile(user.id) : null

  if (!regionCheck) {
    return redirect("/")
  }

  const onboardingModal = user && (
    <OnboardingModal
      customerId={user.id}
      displayName={customerProfile?.display_name ?? null}
    />
  )

  if (!APP_ID || !user)
    return (
      <>
        <Header />
        {onboardingModal}
        {children}
        <Footer />
      </>
    )

  return (
    <>
      <Session appId={APP_ID} userId={user.id}>
        <Header />
        {onboardingModal}
        {children}
        <Footer />
      </Session>
    </>
  )
}

